        java.util.Objects.requireNonNull(presetSpecJson, "presetSpecJson must not be null");
        java.util.Objects.requireNonNull(optionsJson, "optionsJson must not be null");
        return XbergRs.extractStructuredJson(bytes, mime, presetSpecJson, optionsJson);
