    /**
     * Render a single PDF page to PNG bytes.
     *
     * Returns raw PNG-encoded bytes for the specified page at the given DPI.
     * Uses pdf_oxide with tiny-skia for pure-Rust rendering.
     *
     * For pages with extreme dimensions (very wide vector diagrams, etc.) the
     * effective DPI may be automatically reduced to avoid rasterizer failure.
     * A warning is logged when this happens.
     * {@literal @}param pdfBytes Raw PDF file bytes
     *
     * {@literal @}param pageIndex Zero-based page index
     *
     * {@literal @}param dpi Resolution in dots per inch (default: 150)
     *
     * {@literal @}param password Optional password for encrypted PDFs
     *
     * {@literal @}throws XbergRsException Returns {@code XbergError.Parsing} if the PDF cannot be opened, authenticated,
     * or rendered, or if {@code page_index} is out of range.
     */
    public static byte[] renderPdfPageToPng(
        final byte[] pdfBytes,
        final long pageIndex,
        final @Nullable Integer dpi,
        final @Nullable String password
    ) throws XbergRsException {
        java.util.Objects.requireNonNull(pdfBytes, "pdfBytes must not be null");
        java.util.Objects.requireNonNull(pageIndex, "pageIndex must not be null");
        return XbergRs.renderPdfPageToPng(pdfBytes, pageIndex, dpi, password);
    }

    public static byte[] renderPdfPageToPng(final byte[] pdfBytes, final long pageIndex) throws XbergRsException {
        return XbergRs.renderPdfPageToPng(pdfBytes, pageIndex, 0, null);
    }

